"use strict";
const http = require("http");
const os   = require("os");
const { exec } = require("child_process");

const ASSETS = {
  "index.html": "",
  "extrator.html": "",
  "manifest.json": "",
  "sw.js": "",
  "favicon.svg": "",
  "icon-192.png": "",
  "icon-512.png": "",
  "opengraph.jpg": "",
  "assets/app.js": "",
};

const MIME = {
  ".html":"text/html; charset=utf-8",
  ".js":"application/javascript; charset=utf-8",
  ".css":"text/css; charset=utf-8",
  ".json":"application/json",
  ".svg":"image/svg+xml",
  ".png":"image/png",
  ".jpg":"image/jpeg",
};
const PORT = 18633;
function getAsset(url) {
  let key = url.replace(/^\//, "") || "index.html";
  const b = ASSETS[key];
  if (b) return { buf: Buffer.from(b, "base64"), key };
  const idx = ASSETS["index.html"];
  return idx ? { buf: Buffer.from(idx, "base64"), key: "index.html" } : null;
}
const server = http.createServer((req, res) => {
  const a = getAsset(req.url.split("?")[0]);
  if (!a) { res.writeHead(404); res.end("nao encontrado"); return; }
  const ext = a.key.includes(".") ? "."+a.key.split(".").pop() : "";
  res.writeHead(200, { "Content-Type": MIME[ext]||"application/octet-stream","Cache-Control":"no-store" });
  res.end(a.buf);
});
server.listen(PORT, "127.0.0.1", () => {
  const url = "http://127.0.0.1:"+PORT;
  console.log("\n  SK Code Editor Desktop — "+url+"\n  Pressione Ctrl+C para fechar.\n");
  const cmds = { win32:'start "" "'+url+'"', darwin:'open "'+url+'"' };
  exec(cmds[require("os").platform()]||'xdg-open "'+url+'"', ()=>{});
});
server.on("error", e => {
  if (e.code==="EADDRINUSE") console.error("\n  ERRO: porta "+PORT+" em uso. Feche a outra janela.\n");
  else console.error("\n  ERRO:",e.message,"\n");
  process.exit(1);
});
